import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"技能概述","description":"","frontmatter":{},"headers":[],"relativePath":"guide/skills.md","filePath":"guide/skills.md","lastUpdated":1781112327000}'),o={name:"guide/skills.md"};function h(l,t,i,c,n,s){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="技能概述" tabindex="-1">技能概述 <a class="header-anchor" href="#技能概述" aria-label="Permalink to &quot;技能概述&quot;">​</a></h1><p>技能系统是 FunGame 的核心。所有技能都需<strong>继承 <code>Skill</code> 类</strong>来构造。</p><h2 id="技能类型" tabindex="-1">技能类型 <a class="header-anchor" href="#技能类型" aria-label="Permalink to &quot;技能类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>消耗</th><th>吟唱</th><th>升级</th><th>说明</th></tr></thead><tbody><tr><td>普通攻击</td><td>决策点</td><td>❌</td><td>1-8 级</td><td>基于攻击力的物理伤害</td></tr><tr><td>主动战技</td><td>爆发能量</td><td>❌</td><td>1-6 级</td><td>需学习，直接生效</td></tr><tr><td>被动战技</td><td>—</td><td>❌</td><td>通常 1 级</td><td>条件触发，持续生效</td></tr><tr><td>爆发技</td><td>爆发能量</td><td>❌</td><td>1-6 级</td><td>回合外预释放，可插队</td></tr><tr><td>魔法</td><td>魔法值</td><td>✅</td><td>1-8 级</td><td>吟唱后生效</td></tr><tr><td>战斗天赋</td><td>—</td><td>❌</td><td>—</td><td>按定位获取的被动</td></tr></tbody></table><h2 id="技能升级" tabindex="-1">技能升级 <a class="header-anchor" href="#技能升级" aria-label="Permalink to &quot;技能升级&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技能类型</th><th>最高等级</th><th>升级所需等级</th></tr></thead><tbody><tr><td>普通攻击</td><td>8</td><td>8/16/24/32/40/48/56</td></tr><tr><td>主动战技</td><td>6</td><td>12/24/36/48/60</td></tr><tr><td>爆发技</td><td>6</td><td>12/24/36/48/60</td></tr><tr><td>魔法</td><td>8</td><td>8/16/24/32/40/48/56</td></tr></tbody></table><h2 id="施法距离" tabindex="-1">施法距离 <a class="header-anchor" href="#施法距离" aria-label="Permalink to &quot;施法距离&quot;">​</a></h2><table tabindex="0"><thead><tr><th>技能类型</th><th>施法距离</th></tr></thead><tbody><tr><td>普通攻击</td><td>角色攻击距离</td></tr><tr><td>主动战技 / 爆发技</td><td>有施法距离限制</td></tr><tr><td>魔法</td><td>默认全地图</td></tr><tr><td>被动战技</td><td>默认全地图（或指定的生效范围）</td></tr></tbody></table><h2 id="技能范围类型-skillrangetype" tabindex="-1">技能范围类型 (SkillRangeType) <a class="header-anchor" href="#技能范围类型-skillrangetype" aria-label="Permalink to &quot;技能范围类型 (SkillRangeType)&quot;">​</a></h2><p>非指向性技能可以选择不同的范围形状：</p><table tabindex="0"><thead><tr><th>形状</th><th>枚举值</th><th>说明</th></tr></thead><tbody><tr><td>菱形</td><td><code>Diamond</code></td><td>以目标为中心的菱形区域</td></tr><tr><td>圆形</td><td><code>Circle</code></td><td>以目标为中心的圆形区域</td></tr><tr><td>正方形</td><td><code>Square</code></td><td>以目标为中心的正方形区域</td></tr><tr><td>线段</td><td><code>Line</code></td><td>施法者到目标之间的线段</td></tr><tr><td>贯通线</td><td><code>LinePass</code></td><td>施法者到目标的直线，贯穿至地图边缘</td></tr><tr><td>扇形</td><td><code>Sector</code></td><td>以施法者为圆心的扇形区域</td></tr></tbody></table><h2 id="魔法属性-magictype" tabindex="-1">魔法属性 (MagicType) <a class="header-anchor" href="#魔法属性-magictype" aria-label="Permalink to &quot;魔法属性 (MagicType)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>枚举值</th><th>伤害名称</th></tr></thead><tbody><tr><td>无</td><td><code>None</code></td><td>魔法伤害</td></tr><tr><td>星痕</td><td><code>Starmark</code></td><td>星痕魔法伤害</td></tr><tr><td>纯粹结晶</td><td><code>PurityContemporary</code></td><td>纯粹结晶魔法伤害</td></tr><tr><td>现代结晶</td><td><code>PurityNatural</code></td><td>现代结晶魔法伤害</td></tr><tr><td>光</td><td><code>Bright</code></td><td>光魔法伤害</td></tr><tr><td>影</td><td><code>Shadow</code></td><td>影魔法伤害</td></tr><tr><td>元素</td><td><code>Element</code></td><td>元素魔法伤害</td></tr><tr><td>紫宛</td><td><code>Aster</code></td><td>紫宛魔法伤害</td></tr><tr><td>时空</td><td><code>SpatioTemporal</code></td><td>时空魔法伤害</td></tr></tbody></table><p>每种魔法属性有独立的<strong>魔法抗性</strong>，但魔法穿透为共用属性。</p>',14)])])}const u=d(o,[["render",h]]);export{p as __pageData,u as default};
